// Correct nested routes middleware function
function nestedRoutes(req, res, next) {
    if (req.url.startsWith('/admin')) {
        const parts = req.url.split('/admin/');
        if (parts.length > 1) {
            const [base, path] = parts;
            if (path.startsWith('users')) {
                res.send(`Hello from ${base}/${path}`);
            } else {
                next();
            }
        } else {
            next();
        }
    } else {
        next();
    }
}
